const { userId, eventType, eventData } = $input.first().json;

const now = eventData.date || new Date().toISOString().split('T')[0];
let text = '';

switch (eventType) {
  case 'weight_log':
    text = `On ${now}, user logged weight: ${eventData.weight_kg}kg`;
    if (eventData.notes) text += `. Notes: ${eventData.notes}`;
    break;
  case 'meal_reported':
    text = `On ${now}, user ate: ${eventData.meal_description}`;
    if (eventData.calories) text += `. Estimated calories: ${eventData.calories} kcal`;
    if (eventData.meal_type) text += `. Meal type: ${eventData.meal_type}`;
    break;
  case 'profile_update':
    const changes = Object.entries(eventData)
      .filter(([k]) => k !== 'date')
      .map(([k, v]) => `${k}: ${v}`)
      .join(', ');
    text = `On ${now}, user updated profile: ${changes}`;
    break;
  case 'goal_set':
    text = `On ${now}, user set goal: ${eventData.goal_type || 'general'}`;
    if (eventData.target_weight_kg) text += `. Target weight: ${eventData.target_weight_kg}kg`;
    if (eventData.target_date) text += `. Target date: ${eventData.target_date}`;
    if (eventData.description) text += `. Description: ${eventData.description}`;
    break;
  default:
    text = `On ${now}, user event: ${eventType}. Data: ${JSON.stringify(eventData)}`;
}

// Generate a deterministic UUID-like ID from userId + eventType + date
const idBase = `${userId}-${eventType}-${now}-${Date.now()}`;
const pointId = idBase.replace(/[^a-zA-Z0-9]/g, '').substring(0, 32).padEnd(32, '0');
// Format as UUID
const formattedId = [
  pointId.substring(0, 8),
  pointId.substring(8, 12),
  pointId.substring(12, 16),
  pointId.substring(16, 20),
  pointId.substring(20, 32)
].join('-');

return [{
  json: {
    userId,
    eventType,
    eventData,
    text,
    pointId: formattedId,
    date: now
  }
}];
